noncompliant:
// Noncompliant: returns_nonnull on function returning non-pointer
int f1() __attribute__((returns_nonnull));  // Error: returns int, not pointer

void g(int *a) __attribute__((nonnull(1))) {}  // Correct usage
void h() __attribute__((nonnull(1))) {}  // Noncompliant: no parameters

// Noncompliant: malloc attribute on function not returning pointer
int badMalloc() __attribute__((malloc));  // Error: returns int

// Noncompliant: noreturn on function that can return
void mayReturn(bool condition) __attribute__((noreturn)) {
    if (condition) {
        exit(1);
    }
    // This function can return, but marked noreturn
}

compliant:
// Compliant: returns_nonnull on function returning pointer
int* f1() __attribute__((returns_nonnull));

// Compliant: nonnull with correct parameter numbers
void g(int *a, char *b) __attribute__((nonnull(1, 2))) {}

// Compliant: malloc attribute on function returning pointer
void* myMalloc(size_t size) __attribute__((malloc));

// Compliant: noreturn on function that never returns
void terminate() __attribute__((noreturn)) {
    exit(1);  // Always exits
}

// Compliant: pure attribute on function without side effects
int add(int a, int b) __attribute__((pure)) {
    return a + b;  // No side effects
}
